proof fn phi_1_always_unfold_intensional_bridge(ex: Execution<int>, p: TempPred<int>, i: nat)
    requires
        always(p).satisfied_by(ex),
    ensures
        p.satisfied_by(ex.suffix(i)),
{
    always_unfold::<int>(ex, p);
}

proof fn phi_2_not_eventually_from_always_not(ex: Execution<int>, p: TempPred<int>)
    requires
        always(not(p)).satisfied_by(ex),
    ensures
        not(eventually(p)).satisfied_by(ex),
{
    not_eventually_by_always_not::<int>(ex, p);
}

proof fn phi_3_always_not_blocks_any_witness(ex: Execution<int>, p: TempPred<int>, witness: nat)
    requires
        always(not(p)).satisfied_by(ex),
    ensures
        !p.satisfied_by(ex.suffix(witness)),
{
    always_unfold::<int>(ex, not(p));
}

proof fn phi_4_double_not_eventually_collapse(ex: Execution<int>, p: TempPred<int>)
    requires
        always(not(not(p))).satisfied_by(ex),
    ensures
        not(eventually(not(p))).satisfied_by(ex),
{
    not_eventually_by_always_not::<int>(ex, not(p));
}

proof fn phi_5_always_not_self_contradicts_eventually(ex: Execution<int>, p: TempPred<int>)
    requires
        always(not(p)).satisfied_by(ex),
        eventually(p).satisfied_by(ex),
    ensures
        false,
{
    not_eventually_by_always_not::<int>(ex, p);
}
